import{_ as a,o as i,c as t,a7 as s}from"./chunks/framework.CJaX6y8V.js";const h=JSON.parse('{"title":"Swimlane Diagram Config Schema","description":"","frontmatter":{"editLink":"https://github.com/mermaid-js/mermaid/edit/develop/packages/mermaid/src/schemas/config.schema.yaml","head":[["link",{"rel":"canonical","href":"https://mermaid.ai/open-source/config/schema-docs/config-defs-swimlane-diagram-config.html"}]]},"headers":[],"relativePath":"config/schema-docs/config-defs-swimlane-diagram-config.md","filePath":"config/schema-docs/config-defs-swimlane-diagram-config.md"}'),n={name:"config/schema-docs/config-defs-swimlane-diagram-config.md"};function o(l,e,r,d,g,p){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="swimlane-diagram-config-schema" tabindex="-1">Swimlane Diagram Config Schema <a class="header-anchor" href="#swimlane-diagram-config-schema" aria-label="Permalink to &quot;Swimlane Diagram Config Schema&quot;">​</a></h1><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://mermaid.js.org/schemas/config.schema.json#/$defs/SwimlaneDiagramConfig</span></span></code></pre></div><p>The object containing configurations specific for the swimlanes diagram type.</p><p>Swimlanes reuses the flowchart renderer and flowchart config for shared options (curve, htmlLabels, spacing, …); this block holds the knobs that only affect the swimlanes layout pipeline.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Abstract</th><th style="text-align:left;">Extensible</th><th style="text-align:left;">Status</th><th style="text-align:left;">Identifiable</th><th style="text-align:left;">Custom Properties</th><th style="text-align:left;">Additional Properties</th><th style="text-align:left;">Access Restrictions</th><th style="text-align:left;">Defined In</th></tr></thead><tbody><tr><td style="text-align:left;">Can be instantiated</td><td style="text-align:left;">No</td><td style="text-align:left;">Unknown status</td><td style="text-align:left;">No</td><td style="text-align:left;">Forbidden</td><td style="text-align:left;">Allowed</td><td style="text-align:left;">none</td><td style="text-align:left;"><a href="/dochub/mermaid/schemas/config.schema.json" title="open original schema">config.schema.json*</a></td></tr></tbody></table><h2 id="swimlanediagramconfig-type" tabindex="-1">SwimlaneDiagramConfig Type <a class="header-anchor" href="#swimlanediagramconfig-type" aria-label="Permalink to &quot;SwimlaneDiagramConfig Type&quot;">​</a></h2><p><code>object</code> (<a href="./config-defs-swimlane-diagram-config.html">Swimlane Diagram Config</a>)</p><p>all of</p><ul><li><a href="./config-defs-base-diagram-config.html" title="check type definition">Base Diagram Config</a></li></ul><h1 id="swimlanediagramconfig-properties" tabindex="-1">SwimlaneDiagramConfig Properties <a class="header-anchor" href="#swimlanediagramconfig-properties" aria-label="Permalink to &quot;SwimlaneDiagramConfig Properties&quot;">​</a></h1><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Type</th><th style="text-align:left;">Required</th><th style="text-align:left;">Nullable</th><th style="text-align:left;">Defined by</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="#linehops">lineHops</a></td><td style="text-align:left;">Merged</td><td style="text-align:left;">Optional</td><td style="text-align:left;">cannot be null</td><td style="text-align:left;"><a href="./config-defs-swimlane-diagram-config-properties-linehops.html" title="https://mermaid.js.org/schemas/config.schema.json#/$defs/SwimlaneDiagramConfig/properties/lineHops">Mermaid Config</a></td></tr><tr><td style="text-align:left;"><a href="#ignorecrosslaneedges">ignoreCrossLaneEdges</a></td><td style="text-align:left;"><code>boolean</code></td><td style="text-align:left;">Optional</td><td style="text-align:left;">cannot be null</td><td style="text-align:left;"><a href="./config-defs-swimlane-diagram-config-properties-ignorecrosslaneedges.html" title="https://mermaid.js.org/schemas/config.schema.json#/$defs/SwimlaneDiagramConfig/properties/ignoreCrossLaneEdges">Mermaid Config</a></td></tr><tr><td style="text-align:left;"><a href="#optimizeranksbycrossings">optimizeRanksByCrossings</a></td><td style="text-align:left;"><code>boolean</code></td><td style="text-align:left;">Optional</td><td style="text-align:left;">cannot be null</td><td style="text-align:left;"><a href="./config-defs-swimlane-diagram-config-properties-optimizeranksbycrossings.html" title="https://mermaid.js.org/schemas/config.schema.json#/$defs/SwimlaneDiagramConfig/properties/optimizeRanksByCrossings">Mermaid Config</a></td></tr></tbody></table><h2 id="linehops" tabindex="-1">lineHops <a class="header-anchor" href="#linehops" aria-label="Permalink to &quot;lineHops&quot;">​</a></h2><p>Renders edge crossings as small arcs (&quot;hops&quot;) or visible gaps so that overlapping edges are easier to read. Set to <code>false</code> to disable. Edges rendered as curves are skipped to avoid corrupting the geometry.</p><p><code>lineHops</code></p><ul><li><p>is optional</p></li><li><p>Type: merged type (<a href="./config-defs-swimlane-diagram-config-properties-linehops.html">Details</a>)</p></li><li><p>cannot be null</p></li><li><p>defined in: <a href="./config-defs-swimlane-diagram-config-properties-linehops.html" title="https://mermaid.js.org/schemas/config.schema.json#/$defs/SwimlaneDiagramConfig/properties/lineHops">Mermaid Config</a></p></li></ul><h3 id="linehops-type" tabindex="-1">lineHops Type <a class="header-anchor" href="#linehops-type" aria-label="Permalink to &quot;lineHops Type&quot;">​</a></h3><p>merged type (<a href="./config-defs-swimlane-diagram-config-properties-linehops.html">Details</a>)</p><p>one (and only one) of</p><ul><li><p><a href="./config-defs-swimlane-diagram-config-properties-linehops-oneof-0.html" title="check type definition">Untitled boolean in Mermaid Config</a></p></li><li><p><a href="./config-defs-swimlane-diagram-config-properties-linehops-oneof-1.html" title="check type definition">Untitled string in Mermaid Config</a></p></li></ul><h3 id="linehops-default-value" tabindex="-1">lineHops Default Value <a class="header-anchor" href="#linehops-default-value" aria-label="Permalink to &quot;lineHops Default Value&quot;">​</a></h3><p>The default value is:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;arc&quot;</span></span></code></pre></div><h2 id="ignorecrosslaneedges" tabindex="-1">ignoreCrossLaneEdges <a class="header-anchor" href="#ignorecrosslaneedges" aria-label="Permalink to &quot;ignoreCrossLaneEdges&quot;">​</a></h2><p>Ignores edges that cross swimlane boundaries during swimlane layer assignment. This can improve rank quality for diagrams with many cross-lane links.</p><p><code>ignoreCrossLaneEdges</code></p><ul><li><p>is optional</p></li><li><p>Type: <code>boolean</code></p></li><li><p>cannot be null</p></li><li><p>defined in: <a href="./config-defs-swimlane-diagram-config-properties-ignorecrosslaneedges.html" title="https://mermaid.js.org/schemas/config.schema.json#/$defs/SwimlaneDiagramConfig/properties/ignoreCrossLaneEdges">Mermaid Config</a></p></li></ul><h3 id="ignorecrosslaneedges-type" tabindex="-1">ignoreCrossLaneEdges Type <a class="header-anchor" href="#ignorecrosslaneedges-type" aria-label="Permalink to &quot;ignoreCrossLaneEdges Type&quot;">​</a></h3><p><code>boolean</code></p><h3 id="ignorecrosslaneedges-default-value" tabindex="-1">ignoreCrossLaneEdges Default Value <a class="header-anchor" href="#ignorecrosslaneedges-default-value" aria-label="Permalink to &quot;ignoreCrossLaneEdges Default Value&quot;">​</a></h3><p>The default value is:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><h2 id="optimizeranksbycrossings" tabindex="-1">optimizeRanksByCrossings <a class="header-anchor" href="#optimizeranksbycrossings" aria-label="Permalink to &quot;optimizeRanksByCrossings&quot;">​</a></h2><p>Enables a crossing-aware rank optimization pass for swimlane layouts.</p><p><code>optimizeRanksByCrossings</code></p><ul><li><p>is optional</p></li><li><p>Type: <code>boolean</code></p></li><li><p>cannot be null</p></li><li><p>defined in: <a href="./config-defs-swimlane-diagram-config-properties-optimizeranksbycrossings.html" title="https://mermaid.js.org/schemas/config.schema.json#/$defs/SwimlaneDiagramConfig/properties/optimizeRanksByCrossings">Mermaid Config</a></p></li></ul><h3 id="optimizeranksbycrossings-type" tabindex="-1">optimizeRanksByCrossings Type <a class="header-anchor" href="#optimizeranksbycrossings-type" aria-label="Permalink to &quot;optimizeRanksByCrossings Type&quot;">​</a></h3><p><code>boolean</code></p><h3 id="optimizeranksbycrossings-default-value" tabindex="-1">optimizeRanksByCrossings Default Value <a class="header-anchor" href="#optimizeranksbycrossings-default-value" aria-label="Permalink to &quot;optimizeRanksByCrossings Default Value&quot;">​</a></h3><p>The default value is:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div>',40)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
